	if len(users.calls) != 1 || users.calls[0].transaction != dusers.TransactionSale || users.calls[0].amount != 15 {
		t.Fatalf("unexpected user calls: %+v", users.calls)
	}
}

func TestSaleCalculator_Calculate(t *testing.T) {
	calc := saleCalculator{maxDustPerSale: 3}
	pos := &dmarkets.UserPosition{Value: 100}

	result, err := calc.Calculate(pos, 10, 23)
	if err != nil {
		t.Fatalf("expected success, got %v", err)
	}
	if result.SharesToSell != 2 || result.SaleValue != 20 || result.Dust != 3 {
		t.Fatalf("unexpected sale result: %+v", result)
	}

	if _, err := calc.Calculate(pos, 10, 5); !errors.Is(err, ErrInvalidAmount) {
		t.Fatalf("expected ErrInvalidAmount, got %v", err)
	}

	_, err = calc.Calculate(pos, 10, 35)
	var dustErr ErrDustCapExceeded
	if !errors.As(err, &dustErr) {
		t.Fatalf("expected dust cap error, got %v", err)
	}
}

package bets

import (
	"errors"
	"fmt"
)

func newDomainError(message string) error {
	return errors.New(message)
}

var (
	// ErrInvalidOutcome is returned when the bet outcome is not recognised.
	ErrInvalidOutcome = newDomainError("invalid outcome; expected YES or NO")
	// ErrInvalidAmount is returned when the bet amount is not positive.
	ErrInvalidAmount = newDomainError("bet amount must be greater than zero")
	// ErrMarketClosed is returned when a bet is attempted on a closed or resolved market.
	ErrMarketClosed = newDomainError("market is closed or resolved")
	// ErrInsufficientBalance indicates the user would exceed the maximum allowed debt.
	ErrInsufficientBalance = newDomainError("insufficient balance for requested bet")
	// ErrNoPosition indicates the user has no position to sell.
	ErrNoPosition = newDomainError("no position found for the given market and outcome")
	// ErrInsufficientShares indicates the user cannot sell the requested credits.
	ErrInsufficientShares = newDomainError("not enough shares to satisfy requested sale")
)

// ErrDustCapExceeded is returned when a sell transaction would generate dust above the configured cap.
type ErrDustCapExceeded struct {
	Cap       int64
	Requested int64
}

func (e ErrDustCapExceeded) Error() string {
	return fmt.Sprintf("dust cap exceeded: would generate %d dust points (cap: %d)", e.Requested, e.Cap)
}

func (e ErrDustCapExceeded) Is(target error) bool {
	switch target.(type) {
	case ErrDustCapExceeded, *ErrDustCapExceeded:
		return true
	default:
		return false
	}
}

func newDustCapExceeded(cap, requested int64) ErrDustCapExceeded {
	return ErrDustCapExceeded{
		Cap:       cap,
		Requested: requested,
	}
}

package bets

import (
	"time"

	"socialpredict/models"
)

// PlaceRequest captures the inputs required to place a buy bet.
type PlaceRequest struct {
	Username string
	MarketID uint
	Amount   int64
	Outcome  string
}

// NewBet builds the persisted bet record for a place request.
func (r PlaceRequest) NewBet(outcome string, placedAt time.Time) *models.Bet {
	return &models.Bet{
		Username: r.Username,
		MarketID: r.MarketID,
		Amount:   r.Amount,
		Outcome:  outcome,
		PlacedAt: placedAt,
	}
}

// PlacedBet represents the bet that was successfully recorded.
type PlacedBet struct {
	Username string
	MarketID uint
	Amount   int64
	Outcome  string
	PlacedAt time.Time
}

// FromModel copies the persisted bet fields into the domain result shape.
func (p *PlacedBet) FromModel(bet *models.Bet) *PlacedBet {
	if bet == nil {
		return nil
	}
	if p == nil {
		p = &PlacedBet{}
	}
	*p = PlacedBet{
		Username: bet.Username,
		MarketID: bet.MarketID,
		Amount:   bet.Amount,
		Outcome:  bet.Outcome,
		PlacedAt: bet.PlacedAt,
	}
	return p
}

// SellRequest represents a request to sell shares for credits.
type SellRequest struct {
	Username string
	MarketID uint
	Amount   int64 // credits requested
	Outcome  string
}

// NewSaleBet builds the persisted ledger entry for a share sale.
func (r SellRequest) NewSaleBet(outcome string, sharesSold int64, placedAt time.Time) *models.Bet {
	return &models.Bet{
		Username: r.Username,
		MarketID: r.MarketID,
		Amount:   -sharesSold,
		Outcome:  outcome,
		PlacedAt: placedAt,
	}
}

// SellResult summarises the sale that occurred.
type SellResult struct {
	Username      string
	MarketID      uint
	SharesSold    int64
	SaleValue     int64
	Dust          int64
	Outcome       string
	TransactionAt time.Time
}

// Build populates the sell result from the request and calculated sale quote.
func (r *SellResult) Build(req SellRequest, outcome string, sale SaleQuote, transactionAt time.Time) *SellResult {
	if r == nil {
		r = &SellResult{}
	}
	*r = SellResult{
		Username:      req.Username,
		MarketID:      req.MarketID,
		SharesSold:    sale.SharesToSell,
		SaleValue:     sale.SaleValue,
		Dust:          sale.Dust,
		Outcome:       outcome,
		TransactionAt: transactionAt,
	}
	return r
}

