	repo := &fakeRepo{}
	markets := &fakeMarkets{
		getMarketFunc: func(ctx context.Context, id int64) (*dmarkets.Market, error) {
			return &dmarkets.Market{ID: 1, Status: "active", ResolutionDateTime: now.Add(24 * time.Hour)}, nil
