			}, nil
		},
	}
	users := &fakeUsers{getUserFunc: func(ctx context.Context, username string) (*dusers.User, error) {
		return &dusers.User{Username: "alice"}, nil
	}}

	svc := bets.NewService(repo, markets, users, econ, fixedClock{now: now})

	_, err := svc.Sell(context.Background(), bets.SellRequest{
		Username: "alice",
		MarketID: 1,
		Amount:   5, // less than value per share (10)
